import React, { useContext } from 'react';
import { AppContext } from '../context/AppContext';
import { ArrowLeft, Info } from 'lucide-react';
import StepCard from '../components/StepCard';

const Guidance = () => {
    const { navigate } = useContext(AppContext);

    const stepsData = [
        {
            number: 1,
            title: "Get Death Certificate",
            description: "Obtain originals & attested copies from local municipal office or panchayat office.",
            status: "done",
            tags: ["📄 Form 4", "🆔 ID proof"]
        },
        {
            number: 2,
            title: "Visit Home Branch",
            description: "Go to the SBI branch where the deceased held the account. Speak to the branch manager and request the claim forms.",
            status: "active",
            tags: ["💳 Passbook / Card", "📄 Death Cert × 3"]
        },
        {
            number: 3,
            title: "Submit Claim Form",
            description: "Fill SBI Form 1 (Claim Form) with relationship proof and legal heir documents.",
            status: "pending"
        },
        {
            number: 4,
            title: "Indemnity Bond (if applicable)",
            description: "For amounts under ₹5L with no nominee, an indemnity bond on stamp paper replaces the succession certificate.",
            status: "pending"
        },
        {
            number: 5,
            title: "Verification & Processing",
            description: "Bank verifies documents. Typically takes 7–15 working days after submission.",
            status: "pending"
        }
    ];

    return (
        <div style={{
            flex: 1, backgroundColor: 'var(--warm-white)',
            display: 'flex', flexDirection: 'column',
            paddingTop: 'var(--sat)',
            animation: 'slideUp 0.3s cubic-bezier(0.22, 1, 0.36, 1)'
        }}>

            {/* Hero Header */}
            <div style={{
                backgroundColor: 'var(--deep-teal)', padding: '16px 20px 24px',
                color: '#fff', position: 'relative'
            }}>
                <button
                    onClick={() => navigate('dashboard')}
                    style={{
                        width: '40px', height: '40px',
                        backgroundColor: 'rgba(255,255,255,0.1)', borderRadius: '12px',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        marginBottom: '20px'
                    }}
                >
                    <ArrowLeft size={20} color="#fff" />
                </button>

                <div style={{
                    display: 'inline-flex', alignItems: 'center', gap: '6px',
                    padding: '4px 12px', backgroundColor: 'rgba(255,255,255,0.1)',
                    border: '1px solid rgba(201,169,110,0.4)', borderRadius: '20px',
                    color: 'var(--gold)', fontSize: '11px', fontWeight: 600,
                    letterSpacing: '0.5px', textTransform: 'uppercase', marginBottom: '16px'
                }}>
                    🏦 SBI Savings Account
                </div>

                <h1 style={{ fontSize: '32px', lineHeight: 1.2, margin: '0 0 16px 0', color: '#fff' }}>
                    Closing Account Without a Nominee
                </h1>

                <div style={{ display: 'flex', gap: '16px', fontSize: '13px', color: 'rgba(255,255,255,0.7)' }}>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>📄 7 steps</span>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>⏱ ~3–4 weeks</span>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>🏢 Branch visit needed</span>
                </div>
            </div>

            <div className="scroll-container" style={{ flex: 1, padding: '24px 20px 100px' }}>

                {/* Callout */}
                <div style={{
                    backgroundColor: 'var(--pale-teal)', borderRadius: '16px',
                    padding: '16px', display: 'flex', gap: '12px', marginBottom: '32px',
                    border: '1px solid rgba(74,139,139,0.2)'
                }}>
                    <div style={{ color: 'var(--mid-teal)', marginTop: '2px' }}><Info size={20} /></div>
                    <p style={{ margin: 0, fontSize: '14px', lineHeight: 1.5, color: 'var(--text-dark)' }}>
                        <strong>RBI Direction applies:</strong> For balances under ₹5 lakhs with no nominee, a simplified claim using an indemnity bond is available — no succession certificate required.
                    </p>
                </div>

                <div style={{
                    fontSize: '12px', fontWeight: 600, letterSpacing: '1px',
                    color: 'var(--text-light)', marginBottom: '24px'
                }}>
                    STEP-BY-STEP PROCESS
                </div>

                <div style={{ display: 'flex', flexDirection: 'column' }}>
                    {stepsData.map((step, idx) => (
                        <StepCard key={idx} {...step} />
                    ))}
                </div>

            </div>

            {/* Floating Action */}
            <div style={{
                position: 'absolute', bottom: 'var(--nav-h)', left: 0, right: 0,
                backgroundColor: '#fff', borderTop: '1px solid var(--border)',
                padding: '16px 20px', zIndex: 10
            }}>
                <button
                    onClick={() => navigate('documents')}
                    style={{
                        backgroundColor: 'var(--deep-teal)', color: '#fff',
                        fontWeight: 600, padding: '16px', borderRadius: '16px',
                        width: '100%', fontSize: '16px',
                        display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px'
                    }}
                >
                    📝 Generate Claim Letter
                </button>
            </div>

        </div>
    );
};

export default Guidance;
